# errors.py
class AgentError(Exception):
    """Root of all agent-specific errors."""

class TransientError(AgentError):
    """Errors that may succeed on retry."""
    retry_after: float | None = None

class RateLimitError(TransientError):
    def __init__(self, msg: str, retry_after: float | None = None):
        super().__init__(msg)
        self.retry_after = retry_after

class APIError(TransientError):
    def __init__(self, status: int, body: str):
        super().__init__(f"API error {status}: {body[:200]}")
        self.status = status

class FatalError(AgentError):
    """Errors that cannot be retried."""

class ToolParseError(FatalError):
    pass

class UnknownToolError(FatalError):
    pass

