import httpx
from errors import RateLimitError, APIError

def call_llm_api(payload: dict) -> dict:
    try:
        resp = httpx.post("https://api.example.com/v1/chat", json=payload, timeout=30)
    except httpx.TimeoutException as exc:
        raise APIError(0, "request timed out") from exc
    except httpx.ConnectError as exc:
        raise APIError(0, "connection failed") from exc

    if resp.status_code == 429:
        retry_after = float(resp.headers.get("Retry-After", 5))
        raise RateLimitError("rate limited", retry_after=retry_after)
    if resp.status_code >= 500:
        raise APIError(resp.status_code, resp.text)
    if resp.status_code >= 400:
        raise FatalError(f"client error {resp.status_code}: {resp.text[:200]}")
    return resp.json()

