import time, logging
from errors import TransientError, FatalError, ToolParseError

logger = logging.getLogger(__name__)

MAX_RETRIES = 3

def run_tool_with_retry(name: str, args: dict) -> dict:
    for attempt in range(1, MAX_RETRIES + 1):
        try:
            return invoke_tool(name, args)
        except TransientError as exc:
            if attempt == MAX_RETRIES:
                logger.error("tool %s failed after %d attempts", name, MAX_RETRIES)
                raise
            wait = getattr(exc, "retry_after", None) or (2 ** attempt)
            logger.warning("tool %s transient error (attempt %d), retrying in %.1fs",
                           name, attempt, wait)
            time.sleep(wait)
        except ToolParseError as exc:
            # Not retryable — return structured error for the model
            logger.warning("tool %s parse error: %s", name, exc)
            return {"error": str(exc)}
        except FatalError:
            logger.exception("fatal tool error in %s", name)
            raise

