import time, random

def retry_with_backoff(fn, max_attempts=5, base_delay=1.0, max_delay=60.0):
    """Exponential backoff with full jitter."""
    for attempt in range(1, max_attempts + 1):
        try:
            return fn()
        except TransientError as exc:
            if attempt == max_attempts:
                raise
            # full jitter: sleep between 0 and min(cap, base * 2^attempt)
            cap = min(max_delay, base_delay * (2 ** attempt))
            sleep = random.uniform(0, cap)
            time.sleep(sleep)

from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception_type
from errors import RateLimitError, APIError

@retry(
    retry=retry_if_exception_type((RateLimitError, APIError)),
    wait=wait_exponential(multiplier=1, min=1, max=60),
    stop=stop_after_attempt(5),
)
def call_api_with_retry(payload: dict) -> dict:
    return call_llm_api(payload)

# Sanitise before surfacing
def safe_error_message(exc: Exception) -> str:
    """Return a user-safe message; strip internal details."""
    if isinstance(exc, RateLimitError):
        return "The service is temporarily busy. Please try again shortly."
    if isinstance(exc, ToolParseError):
        return "The tool response could not be read. Try rephrasing your request."
    # For unknown errors, return a generic message
    return "An unexpected error occurred. The team has been notified."
